import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Häufig gestellte Fragen für Spieler","description":"Häufig gestellte Fragen für Spieler und Serveradministratoren in Bezug auf Fabric.","frontmatter":{"title":"Häufig gestellte Fragen für Spieler","description":"Häufig gestellte Fragen für Spieler und Serveradministratoren in Bezug auf Fabric.","search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/de_de/players/faq.md","lastUpdated":1739538073000}`);var a={name:`de_de/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Häufig gestellte Fragen für Spieler <a class="header-anchor" href="#h1" aria-label="Permalink to “Häufig gestellte Fragen für Spieler”">​</a></h1><p>Es gibt viele Fragen, die häufig gestellt werden, deshalb haben wir hier eine Liste dieser Fragen zusammengestellt.</p><h2 id="allgemeine-fragen" tabindex="-1">Allgemeine Fragen <a class="header-anchor" href="#allgemeine-fragen" aria-label="Permalink to “Allgemeine Fragen”">​</a></h2><h3 id="welche-minecraft-versionen-werden-von-fabric-unterstutzt" tabindex="-1">Welche Minecraft Versionen werden von Fabric unterstützt? <a class="header-anchor" href="#welche-minecraft-versionen-werden-von-fabric-unterstutzt" aria-label="Permalink to “Welche Minecraft Versionen werden von Fabric unterstützt?”">​</a></h3><p>Offiziell unterstützt Fabric alle Minecraft-Versionen, beginnend mit Snapshot <code>18w43b</code> und höher, sowie Vollversionen beginnend mit Version <code>1.14</code> und höher.</p><h3 id="wo-kann-ich-veroffentlichte-fabric-mods-herunterladen" tabindex="-1">Wo kann ich veröffentlichte Fabric-Mods herunterladen? <a class="header-anchor" href="#wo-kann-ich-veroffentlichte-fabric-mods-herunterladen" aria-label="Permalink to “Wo kann ich veröffentlichte Fabric-Mods herunterladen?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Du solltest immer prüfen, ob Mods aus einer vertrauenswürdigen Quelle stammen. Weitere Informationen zum Finden von Mods findest du in dem Leitfaden <a href="./finding-mods">Vertrauenswürdige Mods finden</a>.</p></div><p>Die meisten Autoren veröffentlichen ihre Mods auf <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> und <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, manche laden sie jedoch auch auf ihre persönliche Website oder auf andere Plattformen wie GitHub hoch.</p><h3 id="wo-kann-ich-vorgemachte-fabric-modpacks-herunterladen" tabindex="-1">Wo kann ich vorgemachte Fabric-Modpacks herunterladen? <a class="header-anchor" href="#wo-kann-ich-vorgemachte-fabric-modpacks-herunterladen" aria-label="Permalink to “Wo kann ich vorgemachte Fabric-Modpacks herunterladen?”">​</a></h3><p>Du kannst vorgefertigte Fabric-Modpacks auf einer Vielzahl von Plattformen finden, beispielsweise:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};